form:Form.form:Scripts:
		function hab_tipofliar(myThis)
{           
	var codLicFliar = Ctrl('codLicFliar').GetXValue().toString();
	if(codLicFliar!='')
	{  
		//si el valor que llega es la licencia - valido que sea de tipo familiar enfermo segun el parametro
		if(myThis.ID()=='oi_licencia')
		{
			Ctrl('oi_familiar_per').SetXValue(""); 

			if(Ctrl("oi_licencia").GetXValue() != '')
			{             
				var cod_lic =  Ctrl("oi_licencia").GetCValue().replace(" ","").split("-");
				var c_lic = cod_lic[0];  			

				if(codLicFliar.toString() == c_lic.toString())
				{	
					Ctrl('oi_familiar_per').SetEnabled(true);
				}      	
				else
				{   
					Ctrl('oi_familiar_per').SetXValue(""); 
					Ctrl('oi_familiar_per').SetEnabled(false);			
				}	
			}		
		}	
	}

	//en onchange del control de licencias tiene que llamar al calcular dias despues de habilitar al combo de tipo de familiar
	calcular_dias(myThis); 		
}


function ValDates()
{             
	if(validarDiasPedidos())
  	{                    
  		var licVal;  
		var nSQL = GetProxy().SQLService();
		licVal = nSQL.GetXML(Ctrl("main").getResource("qry_ValLic"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" f_inicio=\""+Ctrl('f_inicio').GetXValue()+"\" f_fin=\""+Ctrl('f_fin').GetXValue()+"\"/>");



		if(licVal.GetAttr("flag") != "0")
		{                                			
			var xmlRow;
			var msg="La licencia se solapa con:\n";
			for(xmlRow = licVal.FirstChild(); xmlRow!=null; xmlRow=xmlRow.Next()) 
			{
				msg = msg + xmlRow.GetAttr("desc") + "\n";
			}
			alert(msg);	
		}
		else
		{
			Ctrl('main').DoEvent("guardar");  
			Ctrl('e_saldo').SetXValue("");   
		}
	}
}  

var tipLic;  
function validar_f_fin(myThis)
{	                            
	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

	if (myThis.GetXValue() < Ctrl('f_inicio').GetXValue())
	{
		myThis.SetError("La fecha de Fin debe ser posterior o igual a la fecha de Inicio");
		return false;
	}
	else 
		return true;
}

function calcular_dias(myThis)
{       
	//sugiero año corresp. si lo llamo desde f_inicio
	if(((myThis.ID()=='f_inicio') || (myThis.ID()=='oi_personal_emp') || (myThis.ID()=='oi_licencia') || (myThis.ID()=='oi_familiar_per')) && (Ctrl('f_inicio').GetCValue()!=""))
	{         
		sugerirAnoCorresp();
		calcularSaldo();
	} 

	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

 	if (Ctrl('f_fin').GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
 	{ 		
 		if (Ctrl('f_fin').GetXValue() >= Ctrl('f_inicio').GetXValue())
 		{
 			Ctrl('e_cant_dias').SetTypedValue(DiffDays(Ctrl('f_fin').TypedValue(), Ctrl('f_inicio').TypedValue()) + 1);
 		} 
 		else Ctrl('e_cant_dias').SetXValue("");
 	}
 	else Ctrl('e_cant_dias').SetXValue("");     	

 	return true;

}	

function EnableControl()
{              
	var myOBJ=Ctrl("main").GetLastDoc("OBJ");
	if (myOBJ!=null) Ctrl("main").SaveDoc(myOBJ, "OBJ");

 	if (CtrlExists("l_bloqueada"))
 	{
		if (Ctrl("l_bloqueada").GetXValue()=="1")
		{                   
			CtrlEnabled("oi_licencia",false);
			CtrlEnabled("f_inicio",false);
			CtrlEnabled("f_fin",false);
			CtrlEnabled("e_cant_dias",false);
			CtrlEnabled("e_anio_corresp",false);
			CtrlEnabled("e_cant_dias",false);
			CtrlEnabled("f_interrupcion",false);
			CtrlEnabled("DELETE",false);        
			CtrlEnabled("INTERRUPT",true);
		} else
			CtrlEnabled("INTERRUPT",false);
	} else
 	if (CtrlExists("LIST"))
 	{      
 		LIST_onClick(Ctrl("LIST"));
	}

	//cargar saldo en modo registro
	if(Ctrl("main").GetMode()=='EDIT')
	{
		calcularSaldo();
	}

	if(Ctrl("main").GetMode()=='EDIT' || Ctrl("main").GetMode()=='NEW')
	{
		Ctrl('oi_familiar_per').SetEnabled(false);	
	}

	var v_param;

	//Recupero el codigo de la licencia por familiar en el parametro
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();       
	var param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");	

	//Si existe el parametro el cliente controla la licencia
	if (typeof (param.d_valor) != "undefined")
	{
		v_param = param.d_valor.toString();		
	}
	else
	{
		v_param = "";
	} 	

	Ctrl('codLicFliar').SetXValue(v_param); 	
}

function LIST_onClick(myThis)
{                                         
	if (myThis.GetSelectAttrValue("l_bloqueada")=="1")
	{
		CtrlEnabled("DELETE",false);   
		CtrlEnabled("INTERRUPT",true);
	} else
	{
		CtrlEnabled("DELETE",true);   
		CtrlEnabled("INTERRUPT",false);
	}
}

function sugerirAnoCorresp()
{                                
	var fecha = Ctrl("f_inicio").TypedValue().getFullYear()
	Ctrl('e_anio_corresp').SetTypedValue(fecha);
	Ctrl('e_cant_dias').SetXValue("");
	Ctrl('f_fin').SetXValue("");

}

function calcularSaldo()
{	
	if ((Ctrl('e_anio_corresp').GetCValue() != "") || (Ctrl('oi_licencia').GetXValue() != ""))
	{   
	  var licRes;  
	  var nSQL = GetProxy().SQLService();  

	  //Mandar el tipo de familiar a buscar en el query (del familiar que seleccione en el combo de la persona - para que traiga los datos del abm generico)
	  //Le manda el legajo porque tiene que buscar el convenio

	  licRes = nSQL.GetOBJ(Ctrl("main").getResource("qry_datosLic"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" oi_tipo_familiar=\""+Ctrl('oi_tipo_familiar').GetXValue()+"\" />");

	  if(licRes.e_max_dias_anio!='null')	  	  
	  	Ctrl('e_max_dias_anio').SetXValue(licRes.e_max_dias_anio);
	  else
	  	Ctrl('e_max_dias_anio').SetXValue('');

	  if(licRes.e_max_dias_lic!='null')	  	  
	  	Ctrl('e_max_dias_lic').SetXValue(licRes.e_max_dias_lic);
	  else
	  	Ctrl('e_max_dias_lic').SetXValue('');	

	  if(licRes.e_min_meses_antig!='null')	  	  
	  	Ctrl('e_min_meses_antig').SetXValue(licRes.e_min_meses_antig);
	  else
	  	Ctrl('e_min_meses_antig').SetXValue('');	

	  if(licRes.l_max_dias_anio!='null')	  	  
	  	Ctrl('l_max_dias_anio').SetXValue(licRes.l_max_dias_anio);
	  else
	  	Ctrl('l_max_dias_anio').SetXValue('');	

	  if(licRes.l_max_dias_lic!='null')	  	  
	  	Ctrl('l_max_dias_lic').SetXValue(licRes.l_max_dias_lic);
	  else
	  	Ctrl('l_max_dias_lic').SetXValue('');	

	  if(licRes.l_min_meses_antig!='null')	  	  
	  	Ctrl('l_min_meses_antig').SetXValue(licRes.l_min_meses_antig);
	  else
	  	Ctrl('l_min_meses_antig').SetXValue('');	

	  if(licRes.l_acumulativa!='null')	  	  
	  	Ctrl('l_acumulativa').SetXValue(licRes.l_acumulativa);
	  else
	  	Ctrl('l_acumulativa').SetXValue('');	


	  if(licRes.flag == "1") //si encontro el tipo de licencia
	  { 	  	
      if(licRes.l_acumulativa == "0") //tipo de familiar enferno este valor tiene que ser cero
      {
      	//Mandar el familiar que ingreso en el combo - ya que voy a guardar en la licencia_per al familiar - puedo tener licencia de tipo de hijo y tener n hijos - tendria n licencias con sus acumuladores
      	//Siempre pensando en que puedo tener otro tipo de licencia - puede no ir el parametro del familiar		
      	saldoRes = nSQL.GetOBJ(Ctrl("main").getResource("qry_datosLicLeg"), "<PARAM oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" e_anio_corresp=\""+Ctrl('e_anio_corresp').GetXValue()+"\" oi_familiar_per=\""+Ctrl('oi_familiar_per').GetXValue()+"\" />");
      	//NO ACUMULATIVA
				if(saldoRes.flag == "1")
	  		{
	  			if(licRes.e_max_dias_anio!='null')
	  			{
	  				var saldo = licRes.e_max_dias_anio-saldoRes.diasTomados;
						Ctrl('e_saldo').SetXValue(saldo);	  			
	  			}
	  			else
	  			  Ctrl('e_saldo').SetXValue(0-saldoRes.diasTomados);
				}
				else
				{
					if(licRes.e_max_dias_anio!='null')
						Ctrl('e_saldo').SetXValue(licRes.e_max_dias_anio);
					else
						Ctrl('e_saldo').SetXValue('');
				}
	    	return true;			    
      }
  		else
  		{  
  			saldoRes = nSQL.GetOBJ(Ctrl("main").getResource("qry_datosLicLeg_acum"), "<PARAM oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" e_anio_corresp=\""+Ctrl('e_anio_corresp').GetXValue()+"\" />");
  			//ACUMULATIVA
  			if(saldoRes.flag == "1")
	  		{
					Ctrl('e_saldo').SetXValue(saldoRes.saldo);
				}
				else
				{
					if(licRes.e_max_dias_anio!='null')
						Ctrl('e_saldo').SetXValue(licRes.e_max_dias_anio);
					else
						Ctrl('e_saldo').SetXValue('');
				}
	    	return true;

  		}

	  }
		else
		{   
			Ctrl('e_saldo').SetXValue('');
			return true;
		}		
	}

	return true;	
}

function validarDiasPedidos()     
{   
	//Valida si supera el maximo permitido de la licencia
	if(Ctrl('e_max_dias_lic').GetXValue()!='')
	{	           
		/*if(Ctrl('l_max_dias_lic').GetXValue()=="1" && Ctrl('e_cant_dias').TypedValue() > str2number(Ctrl('e_max_dias_lic').GetXValue()))
		{         
			//preguntar si quiere aprobar de todos modos
			alert("La cantidad de días indicados supera el límite permitido por licencia");
			 return false;
		}*/

		if(Ctrl('e_cant_dias').TypedValue() > str2number(Ctrl('e_max_dias_lic').GetXValue()))
		{
			if(Ctrl('l_max_dias_lic').GetXValue()=="1")
			{
				return confirm("La cantidad de días indicados supera el límite permitido por licencia.\n¿Confirma licencia?");				
			}
			else
			{
				alert("La cantidad de días indicados supera el límite permitido por licencia");
			 	return false;
			}
		}
	} 

	//Si tiene tope anual y tiene licencias
	if(Ctrl('e_max_dias_anio').GetXValue()!='' && Ctrl('e_saldo').GetXValue() !='')
	{
		/*if(Ctrl('l_max_dias_anio').GetXValue()=="1" && Ctrl('e_cant_dias').TypedValue() > Ctrl('e_saldo').TypedValue())
		{        
			//El saldo es insuficiente
			//preguntar si quiere aprobar de todos modos
			alert("La cantidad de días de licencia indicados supera el tope anual establecido");
			return false;
		}*/

		if(Ctrl('e_cant_dias').TypedValue() > Ctrl('e_saldo').TypedValue())
		{
			if(Ctrl('l_max_dias_anio').GetXValue()=="1" )
			{
				return confirm("La cantidad de días de licencia indicados supera el tope anual establecido.\n¿Confirma licencia?");				
			}
			else
			{
				alert("La cantidad de días de licencia indicados supera el tope anual establecido.");
				return false;
			}
		}		
	}  

	//Controla que el legajo supere el mínimo de meses de antiguedad para la licencia
	/*if((Ctrl('e_min_meses_antig').GetXValue()!='NULL') && (Ctrl('l_min_meses_antig').GetXValue()==1) && (Ctrl('e_min_meses_antig').GetXValue()>calcularAntiguedad()))  
	{               
		//Cantidad de meses de antiguedad insuficientes, vuelve a generar licencia
		alert("El Legajo no alcanza el mínimo de meses de antigüedad para tomar una licencia de este tipo.");
		return false;
	}*/

	if(Ctrl('e_min_meses_antig').GetXValue()!='' && Ctrl('e_min_meses_antig').GetXValue()>calcularAntiguedad())
	{
		if(Ctrl('l_min_meses_antig').GetXValue()==1)
		{
			return confirm("El Legajo no alcanza el mínimo de meses de antigüedad para tomar una licencia de este tipo.\n¿Confirma licencia?");				
		}
		else
		{
			alert("El Legajo no alcanza el mínimo de meses de antigüedad para tomar una licencia de este tipo.");
			return false;
		}
	}

	return true; 

}                        

//Calcula la antiguedad del legajo en meses
function calcularAntiguedad()
{
	var antiguedad;  
	var nSQL = GetProxy().SQLService();
	antiguedad = nSQL.GetOBJ(Ctrl("main").getResource("qry_Antiguedad"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" />");    

	var d1 = new Date(antiguedad.f_ant_calculo.substr(0,4),parseInt(antiguedad.f_ant_calculo.substr(4,2))-1, antiguedad.f_ant_calculo.substr(6,2));
	var d2 = new Date();     

	return monthDiff(d1,d2);
}                    

//Calcula Diferencia en Meses entre dos Fechas
function monthDiff(d1, d2) {
    var months;
    months = (d2.getFullYear() - d1.getFullYear()) * 12;
    var fechaActual= new Date();        
    //Si la fecha corresponde al corriente año
    if(fechaActual.getFullYear()==d1.getFullYear())
    	{
    	//Si d1 arranca en el primer día no descuenta el primer mes      
    	if(d1.getDay()==1)
    		months -= (d1.getMonth()-1);
    	else
    		months -= d1.getMonth();
    	}
    else
    	{
    	//Si d1 arranca en el primer día no descuenta el primer mes      
    	if(d1.getDay()==0)
    		months -= (d1.getMonth()-1);
    	else
    		months -= d1.getMonth();
    	}	                             

    //Obtiene el último día del mes  
   	var ultimoDia = new Date(2016,d2.getMonth()+1,0); 
   	//Si el último mes se trabajo completo, suma también el último mes 
   	if(d2.getDay()!=ultimoDia.getDay())
    	months += d2.getMonth();
    else
    	months += d2.getMonth()+1;

    return months <= 0 ? 0 : months;
}


function datos_tipo(myThis)
{
	if(Ctrl('oi_familiar_per').GetXValue()!="")
	{
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var param = nSQL.GetOBJ(Ctrl("main").getResource("qry_tipo_fliar"), "<PARAM oi_familiar_per=\""+Ctrl('oi_familiar_per').GetXValue()+"\" />");			
		Ctrl('oi_tipo_familiar').SetXValue(param.oi_tipo_familiar.toString()); 					

		var nombre = Ctrl("oi_familiar_per").GetCValue().split("-");		                                         		                                         			
		Ctrl('o_licencia_per').SetXValue(Trim(nombre[1])); 
		calcular_dias(myThis);
	}
	else
	{
		Ctrl('o_licencia_per').SetXValue(""); 
		Ctrl('oi_tipo_familiar').SetXValue("");
		calcular_dias(Ctrl('oi_licencia'));  		
	}
}

qry:select.qry:xquery:
					for $r in SQL('
SELECT 
	SUM(PER02_LICEN_PER.e_cant_dias) as diasTomados
FROM
	PER02_LICEN_PER
WHERE
	PER02_LICEN_PER.oi_licencia = {#SOURCE:@oi_licencia}
AND
	PER02_LICEN_PER.e_anio_corresp = {#SOURCE:@e_anio_corresp}	
AND
	PER02_LICEN_PER.oi_personal_emp = {#SOURCE:@oi_personal_emp}

{%? (#SOURCE:@oi_familiar_per='') {% AND isnull(PER02_LICEN_PER.oi_familiar_per) %} {% AND PER02_LICEN_PER.oi_familiar_per ={#SOURCE:@oi_familiar_per} %} %}	

			')/ROWS/ROW
